SELECT 

FROM mood_diary d
WHERE d.deleted = 0
  AND d.user_id = #{userId}

    AND (d.title LIKE CONCAT('%', #{keyword}, '%') 
         OR d.content LIKE CONCAT('%', #{keyword}, '%'))


    AND d.mood_type = #{moodType}


    AND d.weather_type = #{weatherType}


    AND d.create_time >= #{startDate}


    AND d.create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)

ORDER BY d.create_time DESC

SELECT 

FROM mood_diary d
WHERE d.id = #{id}
  AND d.user_id = #{userId}
  AND d.deleted = 0
